/* ── Product Card ── */
function ProductCard({ product, t, index, isMobile }) {
  const [hovered, setHovered] = useState(false);

  return (
    <div
      onMouseEnter={() => setHovered(true)}
      onMouseLeave={() => setHovered(false)}
      style={{
        background: hovered ? "#1f0d12" : "#170a0d",
        border: `1px solid ${hovered ? ROSE : "rgba(201,149,106,0.22)"}`,
        borderRadius: 18, overflow:"hidden",
        transition:"all 0.4s cubic-bezier(0.23,1,0.32,1)",
        transform: hovered && !isMobile ? "translateY(-6px)" : "none",
        boxShadow: hovered ? `0 20px 60px rgba(201,149,106,0.18)` : "none",
        cursor:"pointer",
        animation:`fadeUp 0.6s ease both`,
        animationDelay:`${index * 0.08}s`,
      }}
    >
      {/* Image area */}
      <div style={{
        height: isMobile ? 190 : 255,
        background: product.img
          ? `url(${product.img}) center/cover no-repeat`
          : `linear-gradient(160deg, #2a0e14 0%, #150608 100%)`,
        position:"relative", display:"flex", alignItems:"center", justifyContent:"center",
      }}>
        {!product.img && <FloralPlaceholder/>}
        {!product.img && (
          <div style={{
            position:"absolute", bottom:10, left:"50%", transform:"translateX(-50%)",
            color:"rgba(201,149,106,0.4)", fontSize:10, whiteSpace:"nowrap", fontFamily:"Cairo,sans-serif",
          }}>{t.imgPlaceholder}</div>
        )}

        {product.badge && (
          <div style={{
            position:"absolute", top:12,
            [t.dir==="rtl"?"right":"left"]:12,
            background:`linear-gradient(135deg,${ROSE},${BLUSH})`,
            color:"#1A0A0E", fontSize:10, fontWeight:700,
            padding:"3px 11px", borderRadius:20, fontFamily:"Cairo,sans-serif",
          }}>{product.badge}</div>
        )}

        {!isMobile && (
          <div style={{
            position:"absolute", inset:0, background:"rgba(201,149,106,0.07)",
            opacity: hovered?1:0, transition:"opacity 0.3s",
            display:"flex", alignItems:"center", justifyContent:"center",
          }}>
            <div style={{
              border:`1px solid ${ROSE}`, color:ROSE,
              padding:"9px 22px", borderRadius:30, fontSize:12,
              fontFamily:"Cairo,sans-serif",
              opacity:hovered?1:0, transform:hovered?"scale(1)":"scale(0.85)",
              transition:"all 0.3s ease",
            }}>{t.viewDetails}</div>
          </div>
        )}
      </div>

      {/* Info */}
      <div style={{ padding: isMobile?"14px 14px 16px":"18px 20px 20px", direction:t.dir }}>
        <div style={{ fontSize:10, color:ROSE, letterSpacing:2, marginBottom:4, opacity:0.85, fontFamily:"Cairo,sans-serif" }}>
          {product.category}
        </div>
        <div style={{ color:CREAM, fontSize: isMobile?14:16, fontWeight:600, fontFamily:"Cairo,sans-serif", marginBottom:2 }}>
          {product.name}
        </div>
        <div style={{ color:"rgba(255,255,255,0.3)", fontSize:11, marginBottom:12, fontFamily:"Cairo,sans-serif" }}>
          {product.sub}
        </div>
        <div style={{ display:"flex", justifyContent:"space-between", alignItems:"center" }}>
          <div style={{ color:ROSE, fontSize: isMobile?15:18, fontWeight:700, fontFamily:"Cairo,sans-serif" }}>{product.price}</div>
          <button style={{
            background: hovered ? ROSE : "transparent",
            border:`1px solid ${ROSE}`, color: hovered ? "#1A0A0E" : ROSE,
            borderRadius:8, padding: isMobile?"6px 10px":"8px 18px",
            fontSize: isMobile?11:13, cursor:"pointer",
            fontFamily:"Cairo,sans-serif", fontWeight:600, transition:"all 0.3s",
          }}>{t.addCart}</button>
        </div>
      </div>
    </div>
  );
}

